import{_ as t,o as e,c as n,ag as s}from"./chunks/framework.BDReElpY.js";const g=JSON.parse('{"title":"Vex Language: Native SIMD/SIMT Operator Specification","description":"","frontmatter":{},"headers":[],"relativePath":"archive/extra/Auto_Vectorization.md","filePath":"archive/extra/Auto_Vectorization.md"}'),d={name:"archive/extra/Auto_Vectorization.md"};function o(i,a,r,c,p,l){return e(),n("div",null,[...a[0]||(a[0]=[s(`<h1 id="vex-language-native-simd-simt-operator-specification" tabindex="-1">Vex Language: Native SIMD/SIMT Operator Specification <a class="header-anchor" href="#vex-language-native-simd-simt-operator-specification" aria-label="Permalink to &quot;Vex Language: Native SIMD/SIMT Operator Specification&quot;">​</a></h1><p>This document defines the native operators required for Vex&#39;s automatic vectorization engine and their hardware mappings.</p><p><strong>Target Domains:</strong> AI (Tensors), Cryptography, Scientific Computing, String Processing.<br><strong>Philosophy:</strong> &quot;Operator Mapping&quot; and <strong>&quot;Platform Agnostic Lane Sizing&quot;</strong>.<br><strong>Vision:</strong> No special types like <code>simd&lt;T&gt;</code> in code. Standard arrays (<code>[f32]</code>, <code>[i32; N]</code>) are directly processed as vectors. The compiler automatically determines the optimal vector width for the target architecture (AVX2, AVX-512, NEON, SVE).</p><hr><h2 id="automatic-heterogeneous-dispatch-cpu-↔-gpu" tabindex="-1">Automatic Heterogeneous Dispatch (CPU ↔ GPU) <a class="header-anchor" href="#automatic-heterogeneous-dispatch-cpu-↔-gpu" aria-label="Permalink to &quot;Automatic Heterogeneous Dispatch (CPU ↔ GPU)&quot;">​</a></h2><p>Vex&#39;s compiler automatically decides whether to execute parallel operations on CPU (SIMD) or GPU (SIMT) based on a <strong>workload threshold calculation</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>threshold = complexity × data_size × instruction_family_ratio</span></span></code></pre></div><h3 id="threshold-components" tabindex="-1">Threshold Components <a class="header-anchor" href="#threshold-components" aria-label="Permalink to &quot;Threshold Components&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Component</th><th>Description</th><th>Example Values</th></tr></thead><tbody><tr><td><strong>complexity</strong></td><td>Algorithmic complexity of the operation</td><td>1.0 (add), 2.0 (mul), 5.0 (FMA chain)</td></tr><tr><td><strong>data_size</strong></td><td>Number of elements to process</td><td>1K, 1M, 1B elements</td></tr><tr><td><strong>instruction_family_ratio</strong></td><td>Compute-to-memory ratio</td><td>0.3 (memory-bound), 1.0 (balanced), 3.0 (compute-bound)</td></tr></tbody></table><h3 id="dispatch-decision" tabindex="-1">Dispatch Decision <a class="header-anchor" href="#dispatch-decision" aria-label="Permalink to &quot;Dispatch Decision&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>if threshold &gt; GPU_THRESHOLD:</span></span>
<span class="line"><span>    → Emit GPU kernel (CUDA/Metal/Vulkan)</span></span>
<span class="line"><span>else if threshold &gt; SIMD_THRESHOLD:</span></span>
<span class="line"><span>    → Emit wide SIMD loop (AVX-512/SVE)</span></span>
<span class="line"><span>else:</span></span>
<span class="line"><span>    → Emit narrow SIMD or scalar</span></span></code></pre></div><h3 id="user-experience" tabindex="-1">User Experience <a class="header-anchor" href="#user-experience" aria-label="Permalink to &quot;User Experience&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// User writes - platform agnostic</span></span>
<span class="line"><span>let c = a + b;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Compiler decides:</span></span>
<span class="line"><span>// ├─ 1K elements  → AVX-512 (CPU SIMD)</span></span>
<span class="line"><span>// ├─ 1M elements  → GPU kernel dispatch</span></span>
<span class="line"><span>// └─ 1B elements  → Multi-GPU split</span></span></code></pre></div><p><strong>No <code>gpu</code> keyword required.</strong> The compiler analyzes the workload and automatically selects the optimal execution target.</p><hr><h2 id="_1-math-and-ai-core-linear-algebra-core" tabindex="-1">1. Math and AI Core (Linear Algebra Core) <a class="header-anchor" href="#_1-math-and-ai-core-linear-algebra-core" aria-label="Permalink to &quot;1. Math and AI Core (Linear Algebra Core)&quot;">​</a></h2><p>Fundamental arithmetic for high-performance matrix multiplications, neural networks, and physics simulations. Operates on standard arrays.</p><table tabindex="0"><thead><tr><th>Operation</th><th>Operator</th><th>Description</th><th>Hardware (x86/ARM)</th><th>Usage Example</th></tr></thead><tbody><tr><td><strong>Element-wise Add/Sub</strong></td><td><code>+</code>, <code>-</code></td><td>Standard vector addition/subtraction.</td><td><code>VADD</code>, <code>VSUB</code></td><td><code>vec_a + vec_b</code></td></tr><tr><td><strong>Element-wise Mul/Div</strong></td><td><code>*</code>, <code>/</code></td><td>Standard vector multiplication/division.</td><td><code>VMUL</code>, <code>VDIV</code></td><td><code>weights * inputs</code></td></tr><tr><td><strong>Fused Multiply-Add</strong></td><td><code>*+</code></td><td>Multiply and add (single cycle, high precision).</td><td><code>VFMADD</code>, <code>FMLA</code></td><td><code>acc *+ (x, y)</code> (acc += x*y)</td></tr><tr><td><strong>Minimum</strong></td><td><code>&lt;?</code></td><td>Select the smaller of two vectors.</td><td><code>VMIN</code>, <code>FMIN</code></td><td><code>vec_a &lt;? vec_b</code></td></tr><tr><td><strong>Maximum</strong></td><td><code>&gt;?</code></td><td>Select the larger of two vectors.</td><td><code>VMAX</code>, <code>FMAX</code></td><td><code>vec_a &gt;? vec_zero</code> (ReLU)</td></tr><tr><td><strong>Remainder</strong></td><td><code>%</code></td><td>Modulo (for float and int).</td><td><code>VREM</code></td><td><code>indices % v_size</code></td></tr><tr><td><strong>Negation</strong></td><td><code>-</code></td><td>Sign flip (Unary).</td><td><code>VNEG</code></td><td><code>-vec_velocity</code></td></tr></tbody></table><h3 id="example-relu-activation-function" tabindex="-1">Example: ReLU Activation Function <a class="header-anchor" href="#example-relu-activation-function" aria-label="Permalink to &quot;Example: ReLU Activation Function&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// No &quot;simd&lt;T&gt;&quot; - standard array type [f32] is used directly.</span></span>
<span class="line"><span>// Compiler auto-vectorizes this.</span></span>
<span class="line"><span>fn relu(x: [f32]): [f32] {</span></span>
<span class="line"><span>    return x &gt;? 0.0; // Single instruction: VMAXPS (width-independent)</span></span>
<span class="line"><span>}</span></span></code></pre></div><hr><h2 id="_2-saturating-arithmetic" tabindex="-1">2. Saturating Arithmetic <a class="header-anchor" href="#_2-saturating-arithmetic" aria-label="Permalink to &quot;2. Saturating Arithmetic&quot;">​</a></h2><p>Critical for image processing, DSP, and audio processing. On overflow, values clamp to limits instead of wrapping.</p><table tabindex="0"><thead><tr><th>Operation</th><th>Operator</th><th>Description</th><th>Hardware (x86/ARM)</th><th>Usage Example</th></tr></thead><tbody><tr><td><strong>Saturating Add</strong></td><td><code>+|</code></td><td>Add and clamp at limit (0xFF or MAX_INT).</td><td><code>PADDS</code>, <code>UQADD</code></td><td><code>pixels +| brightness</code></td></tr><tr><td><strong>Saturating Sub</strong></td><td><code>-|</code></td><td>Subtract and clamp at limit (0 or MIN_INT).</td><td><code>PSUBS</code>, <code>UQSUB</code></td><td><code>pixels -| amount</code></td></tr><tr><td><strong>Saturating Mul</strong></td><td><code>*|</code></td><td>Multiply and clamp at limit.</td><td>(Custom/Intrinsic)</td><td><code>audio *| gain</code></td></tr></tbody></table><hr><h2 id="_3-cryptography-and-bit-manipulation-crypto-core" tabindex="-1">3. Cryptography and Bit Manipulation (Crypto Core) <a class="header-anchor" href="#_3-cryptography-and-bit-manipulation-crypto-core" aria-label="Permalink to &quot;3. Cryptography and Bit Manipulation (Crypto Core)&quot;">​</a></h2><p>Native support for blockchain, hashing (SHA/Blake3), and encryption (AES/ChaCha) algorithms.</p><table tabindex="0"><thead><tr><th>Operation</th><th>Operator</th><th>Description</th><th>Hardware (x86/ARM)</th><th>Usage Example</th></tr></thead><tbody><tr><td><strong>Rotate Left</strong></td><td><code>&lt;&lt;&lt;</code></td><td>Circular left shift (no overflow).</td><td><code>PROL</code>, <code>VSHL</code></td><td><code>hash &lt;&lt;&lt; 12</code></td></tr><tr><td><strong>Rotate Right</strong></td><td><code>&gt;&gt;&gt;</code></td><td>Circular right shift.</td><td><code>PROR</code>, <code>VSHR</code></td><td><code>x &gt;&gt;&gt; 7</code></td></tr><tr><td><strong>XOR</strong></td><td><code>^</code></td><td>Bitwise Exclusive OR.</td><td><code>PXOR</code>, <code>EOR</code></td><td><code>state ^ key</code></td></tr><tr><td><strong>AND / OR</strong></td><td><code>&amp;</code>, <code>|</code></td><td>Bitwise AND / OR.</td><td><code>PAND</code>, <code>POR</code></td><td><code>mask &amp; value</code></td></tr><tr><td><strong>NOT</strong></td><td><code>~</code></td><td>Bitwise Inversion.</td><td><code>PANDN</code>, <code>MVN</code></td><td><code>~mask</code></td></tr><tr><td><strong>Carry-less Mul</strong></td><td><code>*^</code></td><td>Galois Field multiplication (polynomial multiply).</td><td><code>PCLMULQDQ</code>, <code>PMULL</code></td><td><code>gcm_tag *^ key</code></td></tr><tr><td><strong>Population Count</strong></td><td><code>.popcnt()</code></td><td>Count set bits (method syntax).</td><td><code>VPOPCNT</code></td><td><code>bitmap.popcnt()</code></td></tr></tbody></table><h3 id="example-simple-hash-round" tabindex="-1">Example: Simple Hash Round <a class="header-anchor" href="#example-simple-hash-round" aria-label="Permalink to &quot;Example: Simple Hash Round&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// [u32] used for width-independent code</span></span>
<span class="line"><span>state ^= (input + key);</span></span>
<span class="line"><span>state = state &lt;&lt;&lt; 13;</span></span>
<span class="line"><span>state = state *+ (prime, 1); // FMA usage</span></span></code></pre></div><hr><h2 id="_4-vector-logic-and-masking-logic-control" tabindex="-1">4. Vector Logic and Masking (Logic &amp; Control) <a class="header-anchor" href="#_4-vector-logic-and-masking-logic-control" aria-label="Permalink to &quot;4. Vector Logic and Masking (Logic &amp; Control)&quot;">​</a></h2><p>Foundation for &quot;Branchless Programming&quot; - string search, JSON parsing, and conditional operations.</p><table tabindex="0"><thead><tr><th>Operation</th><th>Operator</th><th>Description</th><th>Hardware Result</th><th>Usage</th></tr></thead><tbody><tr><td><strong>Compare Eq</strong></td><td><code>==</code></td><td>Equality check.</td><td><code>[bool]</code> (Mask)</td><td><code>chars == &#39; &#39;</code></td></tr><tr><td><strong>Compare Neq</strong></td><td><code>!=</code></td><td>Inequality.</td><td><code>[bool]</code> (Mask)</td><td><code>chars != 0</code></td></tr><tr><td><strong>Compare Gt/Lt</strong></td><td><code>&gt;</code>, <code>&lt;</code></td><td>Greater than / Less than.</td><td><code>[bool]</code> (Mask)</td><td><code>vals &gt; threshold</code></td></tr><tr><td><strong>Select / Blend</strong></td><td><code>? :</code></td><td>Ternary operator (mask-based selection).</td><td><code>VPBLEND</code>, <code>BSL</code></td><td><code>mask ? val_a : val_b</code></td></tr></tbody></table><h3 id="example-masking-whitespace-in-strings" tabindex="-1">Example: Masking Whitespace in Strings <a class="header-anchor" href="#example-masking-whitespace-in-strings" aria-label="Permalink to &quot;Example: Masking Whitespace in Strings&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// load_chunk loads platform&#39;s vector width worth of data</span></span>
<span class="line"><span>let chars: [u8] = load_chunk(ptr);</span></span>
<span class="line"><span>let space_mask = (chars == &#39; &#39;); // Creates mask (returns [bool])</span></span>
<span class="line"><span>let non_spaces = space_mask ? 0 : chars; // Branchless filter</span></span></code></pre></div><hr><h2 id="_5-memory-and-conversion-memory-cast" tabindex="-1">5. Memory and Conversion (Memory &amp; Cast) <a class="header-anchor" href="#_5-memory-and-conversion-memory-cast" aria-label="Permalink to &quot;5. Memory and Conversion (Memory &amp; Cast)&quot;">​</a></h2><p>For AI model quantization (f32 → int8) and sparse data access.</p><table tabindex="0"><thead><tr><th>Operation</th><th>Syntax</th><th>Description</th><th>Hardware</th></tr></thead><tbody><tr><td><strong>Broadcast</strong></td><td><code>[T](scalar)</code></td><td>Spread scalar to all vector lanes.</td><td><code>VPBROADCAST</code></td></tr><tr><td><strong>Cast (Safe)</strong></td><td><code>as</code></td><td>Type conversion (e.g., f32 → i32).</td><td><code>CVTPS2DQ</code></td></tr><tr><td><strong>Reinterpret</strong></td><td><code>bitcast&lt;T&gt;</code></td><td>Change type without changing bits.</td><td>No-op (Compiler)</td></tr><tr><td><strong>Gather</strong></td><td><code>base[indices]</code></td><td>Scattered read using index vector.</td><td><code>VGATHER</code></td></tr><tr><td><strong>Scatter</strong></td><td><code>base[indices] = v</code></td><td>Scattered write using index vector.</td><td><code>VSCATTER</code></td></tr></tbody></table><hr><h2 id="_6-advanced-math-and-transcendental" tabindex="-1">6. Advanced Math and Transcendental <a class="header-anchor" href="#_6-advanced-math-and-transcendental" aria-label="Permalink to &quot;6. Advanced Math and Transcendental&quot;">​</a></h2><p>For scientific computing, physics engines, and game development.</p><table tabindex="0"><thead><tr><th>Operation</th><th>Syntax</th><th>Description</th><th>Hardware (x86/ARM)</th><th>Priority</th></tr></thead><tbody><tr><td><strong>Square Root</strong></td><td><code>.sqrt()</code></td><td>Compute square root.</td><td><code>VSQRT</code></td><td>High (Physics)</td></tr><tr><td><strong>Inv. Square Root</strong></td><td><code>.rsqrt()</code></td><td>Inverse square root (1/sqrt). Very fast.</td><td><code>VRSQRT</code></td><td>Critical (Normalization)</td></tr><tr><td><strong>Absolute</strong></td><td><code>.abs()</code></td><td>Absolute value.</td><td><code>VABS</code></td><td>Medium</td></tr><tr><td><strong>Round/Floor/Ceil</strong></td><td><code>.round()</code></td><td>Rounding operations.</td><td><code>VROUND</code></td><td>Medium</td></tr><tr><td><strong>Reciprocal</strong></td><td><code>.rcp()</code></td><td>Multiplicative inverse (1/x). Used instead of division.</td><td><code>VRCP</code></td><td>High (Optimization)</td></tr></tbody></table><h3 id="example-fast-vector-normalization" tabindex="-1">Example: Fast Vector Normalization <a class="header-anchor" href="#example-fast-vector-normalization" aria-label="Permalink to &quot;Example: Fast Vector Normalization&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fn normalize(v: [f32]): [f32] {</span></span>
<span class="line"><span>    let mag_sq = (v * v).sum();</span></span>
<span class="line"><span>    // 1/sqrt(mag_sq) in a single instruction</span></span>
<span class="line"><span>    return v * mag_sq.rsqrt(); </span></span>
<span class="line"><span>}</span></span></code></pre></div><hr><h2 id="_7-data-manipulation-shuffle-permute" tabindex="-1">7. Data Manipulation (Shuffle &amp; Permute) <a class="header-anchor" href="#_7-data-manipulation-shuffle-permute" aria-label="Permalink to &quot;7. Data Manipulation (Shuffle &amp; Permute)&quot;">​</a></h2><p>Rearranges data in registers instead of memory. Essential for &quot;AoS to SoA&quot; conversions.</p><table tabindex="0"><thead><tr><th>Operation</th><th>Syntax</th><th>Description</th><th>Hardware</th></tr></thead><tbody><tr><td><strong>Shuffle</strong></td><td><code>.shuffle(mask)</code></td><td>Permute vector elements.</td><td><code>VPSHUFFLE</code>, <code>VTBL</code></td></tr><tr><td><strong>Interleave</strong></td><td><code>.zip(vec2)</code></td><td>Interleave two vectors like a zipper.</td><td><code>UNPCK</code>, <code>ZIP1/2</code></td></tr><tr><td><strong>Extract</strong></td><td><code>[index]</code></td><td>Extract scalar from vector (compile-time index).</td><td><code>PEXTR</code>, <code>MOV</code></td></tr></tbody></table><hr><h2 id="_8-precision-management-widening-narrowing" tabindex="-1">8. Precision Management (Widening &amp; Narrowing) <a class="header-anchor" href="#_8-precision-management-widening-narrowing" aria-label="Permalink to &quot;8. Precision Management (Widening &amp; Narrowing)&quot;">​</a></h2><p>Critical for AI quantization (Int8). Writes operation results to larger types to prevent overflow.</p><table tabindex="0"><thead><tr><th>Operation</th><th>Syntax</th><th>Description</th><th>Hardware</th><th>Usage</th></tr></thead><tbody><tr><td><strong>Widen Mul</strong></td><td><code>.mul_wide(v)</code></td><td><code>i8 * i8</code> → <code>i16</code> result.</td><td><code>PMULLW</code></td><td>Quantization</td></tr><tr><td><strong>Narrow</strong></td><td><code>.narrow()</code></td><td>Compress <code>i16</code> to <code>i8</code> (with saturation).</td><td><code>PACKSS</code></td><td>Output compression</td></tr></tbody></table><hr><h2 id="_9-reduction-methods" tabindex="-1">9. Reduction Methods <a class="header-anchor" href="#_9-reduction-methods" aria-label="Permalink to &quot;9. Reduction Methods&quot;">​</a></h2><p>Operations that reduce a vector to a single scalar.</p><table tabindex="0"><thead><tr><th>Method</th><th>Description</th><th>Example</th></tr></thead><tbody><tr><td><code>.sum()</code></td><td>Horizontal sum.</td><td><code>dot_prod = (a * b).sum()</code></td></tr><tr><td><code>.min()</code> / <code>.max()</code></td><td>Smallest/largest element in vector.</td><td><code>min_val = vec.min()</code></td></tr><tr><td><code>.all()</code></td><td>Do all elements match the mask?</td><td><code>if (vec &gt; 0).all() { ... }</code></td></tr><tr><td><code>.any()</code></td><td>Does any element match?</td><td><code>if (vec == error_code).any() { ... }</code></td></tr></tbody></table><hr><h2 id="_10-real-world-examples" tabindex="-1">10. Real-World Examples <a class="header-anchor" href="#_10-real-world-examples" aria-label="Permalink to &quot;10. Real-World Examples&quot;">​</a></h2><h3 id="_10-1-game-development-particle-physics-engine" tabindex="-1">10.1 Game Development: Particle Physics Engine <a class="header-anchor" href="#_10-1-game-development-particle-physics-engine" aria-label="Permalink to &quot;10.1 Game Development: Particle Physics Engine&quot;">​</a></h3><p>Normalizing velocity vectors for thousands of particles in a physics engine.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>struct ParticleSystem {</span></span>
<span class="line"><span>    // Platform-independent vector types (standard arrays)</span></span>
<span class="line"><span>    vx: [f32], </span></span>
<span class="line"><span>    vy: [f32],</span></span>
<span class="line"><span>    vz: [f32]</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>fn normalize_particles(p: &amp;ParticleSystem!) {</span></span>
<span class="line"><span>    // Compiler uses widest register for target architecture</span></span>
<span class="line"><span>    let mag_sq = (p.vx * p.vx) + (p.vy * p.vy) + (p.vz * p.vz);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    let inv_mag = mag_sq.rsqrt();</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    p.vx = p.vx * inv_mag;</span></span>
<span class="line"><span>    p.vy = p.vy * inv_mag;</span></span>
<span class="line"><span>    p.vz = p.vz * inv_mag;</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="_10-2-cryptography-chacha20-quarter-round" tabindex="-1">10.2 Cryptography: ChaCha20 Quarter Round <a class="header-anchor" href="#_10-2-cryptography-chacha20-quarter-round" aria-label="Permalink to &quot;10.2 Cryptography: ChaCha20 Quarter Round&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// [u32]: 8 operations on AVX2, 16 operations on AVX-512 simultaneously</span></span>
<span class="line"><span>fn quarter_round(a: &amp;[u32]!, b: &amp;[u32]!, c: &amp;[u32]!, d: &amp;[u32]!) {</span></span>
<span class="line"><span>    *a = *a + *b;  *d = *d ^ *a;  *d = *d &lt;&lt;&lt; 16;</span></span>
<span class="line"><span>    *c = *c + *d;  *b = *b ^ *c;  *b = *b &lt;&lt;&lt; 12;</span></span>
<span class="line"><span>    *a = *a + *b;  *d = *d ^ *a;  *d = *d &lt;&lt;&lt; 8;</span></span>
<span class="line"><span>    *c = *c + *d;  *b = *b ^ *c;  *b = *b &lt;&lt;&lt; 7;</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="_10-3-ai-ml-cosine-similarity-embedding-comparison" tabindex="-1">10.3 AI/ML: Cosine Similarity (Embedding Comparison) <a class="header-anchor" href="#_10-3-ai-ml-cosine-similarity-embedding-comparison" aria-label="Permalink to &quot;10.3 AI/ML: Cosine Similarity (Embedding Comparison)&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fn cosine_similarity(v1: [f32], v2: [f32]): f32 {</span></span>
<span class="line"><span>    let dot = (v1 * v2).sum(); </span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    let mag_v1 = (v1 * v1).sum();</span></span>
<span class="line"><span>    let mag_v2 = (v2 * v2).sum();</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    return dot * (mag_v1 * mag_v2).rsqrt();</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="_10-4-image-processing-brightness-increase" tabindex="-1">10.4 Image Processing: Brightness Increase <a class="header-anchor" href="#_10-4-image-processing-brightness-increase" aria-label="Permalink to &quot;10.4 Image Processing: Brightness Increase&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fn increase_brightness(pixels: [u8], amount: [u8]): [u8] {</span></span>
<span class="line"><span>    // +| operator (Saturating Add) works hardware-independently</span></span>
<span class="line"><span>    return pixels +| amount; </span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="_10-5-web-backend-simd-json-scanner-whitespace-skipping" tabindex="-1">10.5 Web/Backend: SIMD JSON Scanner (Whitespace Skipping) <a class="header-anchor" href="#_10-5-web-backend-simd-json-scanner-whitespace-skipping" aria-label="Permalink to &quot;10.5 Web/Backend: SIMD JSON Scanner (Whitespace Skipping)&quot;">​</a></h3><p>The most time-consuming task in JSON parsers is finding whitespace and structural characters.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// &#39;load_chunk&#39; loads appropriate width data for the platform</span></span>
<span class="line"><span>fn scan_json_chunk(ptr: *u8): i32 {</span></span>
<span class="line"><span>    let chars: [u8] = load_chunk(ptr);</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    let mask_quote = (chars == &#39;&quot;&#39;);</span></span>
<span class="line"><span>    let mask_brace = (chars == &#39;{&#39;) | (chars == &#39;}&#39;);</span></span>
<span class="line"><span>    let mask_colon = (chars == &#39;:&#39;);</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    let interesting = mask_quote | mask_brace | mask_colon;</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    // to_bitmask() returns appropriate integer for vector length</span></span>
<span class="line"><span>    let bitmask = interesting.to_bitmask(); </span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    if bitmask == 0 {</span></span>
<span class="line"><span>        return -1; </span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    return bitmask.ctz();</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="_10-6-string-processing-fast-substring-search" tabindex="-1">10.6 String Processing: Fast Substring Search <a class="header-anchor" href="#_10-6-string-processing-fast-substring-search" aria-label="Permalink to &quot;10.6 String Processing: Fast Substring Search&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fn find_substring_simd(haystack: *u8, len: i32, needle_char: u8): i32 {</span></span>
<span class="line"><span>    let v_needle: [u8] = [u8](needle_char); // Broadcast</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    // Loop step automatically determined by platform&#39;s vector width (simd_width)</span></span>
<span class="line"><span>    for i in 0..len step sys.SIMD_WIDTH {</span></span>
<span class="line"><span>        let chunk = load_chunk(haystack + i);</span></span>
<span class="line"><span>        </span></span>
<span class="line"><span>        let eq = (chunk == v_needle);</span></span>
<span class="line"><span>        let mask = eq.to_bitmask();</span></span>
<span class="line"><span>        </span></span>
<span class="line"><span>        if mask != 0 {</span></span>
<span class="line"><span>            return i + mask.ctz();</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>    return -1;</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="_10-7-batch-validation-ascii-numeric-check" tabindex="-1">10.7 Batch Validation: ASCII/Numeric Check <a class="header-anchor" href="#_10-7-batch-validation-ascii-numeric-check" aria-label="Permalink to &quot;10.7 Batch Validation: ASCII/Numeric Check&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fn is_numeric_ascii(input: [u8]): bool {</span></span>
<span class="line"><span>    let ge_zero = input &gt;= &#39;0&#39;;</span></span>
<span class="line"><span>    let le_nine = input &lt;= &#39;9&#39;;</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    let is_digit = ge_zero &amp; le_nine;</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    return is_digit.all();</span></span>
<span class="line"><span>}</span></span></code></pre></div>`,76)])])}const u=t(d,[["render",o]]);export{g as __pageData,u as default};
